/** Seconds a flinch (hurt) lasts before the enemy resumes chasing. */
const HURT_TIME = 0.25
/** Seconds the death animation plays before the enemy becomes a static corpse. */
const DYING_TIME = 0.6
/** Seconds the attack pose is held after a swing/shot. */
const ATTACK_POSE_TIME = 0.3
/** Walk-cycle frame cadence (seconds per frame). */
const WALK_FRAME_TIME = 0.18
/** Half-angle (radians) of aim jitter applied to enemy attacks and chase wander. */
const AIM_JITTER = 0.06
/** Mancubus FATSPREAD: ANG90/8 = 11.25° between fan shots. */
const FAT_SPREAD = Math.PI / 2 / 8
/** Blur (partial invisibility) aim penalty vs the player: hitscan ~±0.4 rad, projectile ~±0.2 rad. */
const BLUR_HITSCAN_OFFSET = 0.4
const BLUR_PROJECTILE_OFFSET = 0.2
/** A hitscan bullet whips wide of the player when its blur offset exceeds this. */
const BLUR_HITSCAN_MISS = 0.22

/**
 * Which typed missile each projectile monster fires (doomBehaviorSpec.md §3.3):
 * caco→cacoball, hellKnight/baron→baronball, mancubus→fatshot, arachnotron→aplasma,
 * revenant→tracer (homing); the imp keeps the classic fireball.
 */
const ENEMY_PROJECTILE: Partial<Record<EnemyKind, ProjectileKind>> = {
  imp: 'fireball',
  cacodemon: 'cacoball',
  hellKnight: 'baronball',
  baron: 'baronball',
  mancubus: 'fatshot',
  arachnotron: 'aplasma',
  revenant: 'tracer',
  // Cyberdemon fires a tight burst of splash rockets aimed at the player; it is
  // splashImmune so its own blasts never stagger it (doomBehaviorSpec.md §3.1).
  cyberdemon: 'rocket',
}

/** Arch-vile FIRE attack (doomBehaviorSpec.md §3.1): flat base 20 + 0..70 distance falloff. */
const VILE_FIRE_BASE = 20
const VILE_FIRE_FALLOFF = 70
/** Falloff reaches 0 at this range (cells); inside it scales 70→0 with distance. */
const VILE_FIRE_RANGE = 12

